class Solution {
    double r, xc, yc;
    mt19937 gen;
    uniform_real_distribution<double> dis;
public:
    Solution(double radius, double x_center, double y_center) 
        : r(radius), xc(x_center), yc(y_center), gen(random_device{}()), dis(-1.0, 1.0) {}

    vector<double> randPoint() {
        double x, y;
        do {
            x = dis(gen);
            y = dis(gen);
        } while (x * x + y * y > 1.0);
        return {xc + r * x, yc + r * y};
    }
};
```
